package com.cognizant.product.controller;import com.cognizant.product.model.Product;import com.cognizant.product.repository.ProductRepository;import org.springframework.web.bind.annotation.*;import java.util.List;@RestController @RequestMapping("/products") public class ProductController{private final ProductRepository repo;public ProductController(ProductRepository repo){this.repo=repo;}@GetMapping public List<Product> all(){return repo.findAll();}@GetMapping("/{id}") public Product one(@PathVariable Long id){return repo.findById(id).orElseThrow();}@PostMapping public Product create(@RequestBody Product x){return repo.save(x);}}